		///////////////////////////////////////////////////////////////////////////////          
//EVENTOS
function CustomOnLoad()
{
	OnLoad();             
	RefreshPreview();

}

function TableSCHEDULER_Refresh()
{
	Ctrl("TableSCHEDULER").processResult(dataRows.ToString());
	CtrlEnabled("TableSCHEDULER_EDT", Ctrl("TableSCHEDULER").TotalRowsCount()==0?false:true);
	CtrlEnabled("TableSCHEDULER_DEL", Ctrl("TableSCHEDULER").TotalRowsCount()==0?false:true);

	CtrlEnabled("TableSCHEDULER_UP", Ctrl("TableSCHEDULER").TotalRowsCount()>1?true:false);
	CtrlEnabled("TableSCHEDULER_DW", Ctrl("TableSCHEDULER").TotalRowsCount()>1?true:false);
}

function TableGADGET_Refresh()
{
	Ctrl("TableGADGET").processResult(dataRows.ToString());
	CtrlEnabled("TableGADGET_EDT", Ctrl("TableGADGET").TotalRowsCount()==0?false:true);
}


var dataRows;
var valuesRows=null;

function RefreshPreview()
{         
	//Concateno los text
	var TXT="";


	if (Ctrl("preview") && Ctrl("oi_file"))
		if (Ctrl("oi_file").GetXValue()!="")
			Ctrl("preview").SetURL("../../../GenFiles/"+GetProxy().AppName()+"/PREVIEW/PAGE."+Ctrl("ID").GetXValue()+".LANG.html?now="+datetime2str(Now()));

	if (Ctrl("WikiText"))
	{
		TXT+=Ctrl("o_text1").GetXValue();
		TXT+=Ctrl("o_text2").GetXValue();
		TXT+=Ctrl("o_text3").GetXValue();
		TXT+=Ctrl("o_text4").GetXValue();		

		//Eventos
		Ctrl("WikiText").OpenImage =OpenImage;
		Ctrl("WikiText").OpenWindow=OpenLink;
		Ctrl("WikiText").Goto      =OpenLink;

		//Concateno los text
		Ctrl("WikiText").SetXValue(TXT);
	}

	if (Ctrl("TableHTML"))
	{
		TXT+=Ctrl("o_text1").GetXValue();
		TXT+=Ctrl("o_text2").GetXValue();
		TXT+=Ctrl("o_text3").GetXValue();
		TXT+=Ctrl("o_text4").GetXValue();		

		if (TXT=="")
			TXT='<TABLE ><COLS><COL width="100" /></COLS><ROWS><TR height="*" ><TD union="N" control="SC" ></TD></TR></ROWS></TABLE>';

		//Concateno los text
		Ctrl("TableHTML").Mode="EDIT";
		Ctrl("TableHTML").Config=new nomadDOM(TXT);
		Ctrl("TableHTML").SyncHTML();
	}                                

	if (Ctrl("TableSCHEDULER"))
	{
		TXT+=Ctrl("o_text1").GetXValue();
		TXT+=Ctrl("o_text2").GetXValue();
		TXT+=Ctrl("o_text3").GetXValue();
		TXT+=Ctrl("o_text4").GetXValue();		

		if (TXT=="")
			TXT='<ROWS></ROWS>';

    dataRows=new NomadXML(TXT);
		TableSCHEDULER_Refresh();
	}                                

	if (Ctrl("TableGADGET"))
	{
		TXT+=Ctrl("o_text1").GetXValue();
		TXT+=Ctrl("o_text2").GetXValue();
		TXT+=Ctrl("o_text3").GetXValue();
		TXT+=Ctrl("o_text4").GetXValue();		

		if (TXT=="")
			TXT='<ROWS></ROWS>';

    dataRows=new NomadXML(TXT);
		TableGADGET_Refresh();
	}                                
}


function SplitText()
{
	if (Ctrl("WikiText") || Ctrl("TableHTML") || Ctrl("TableSCHEDULER") || Ctrl("TableGADGET"))
	{      

		var TextS=new Array();
		var TextAll;

		if (Ctrl("WikiText" )) TextAll=Ctrl("WikiText").GetXValue();
		if (Ctrl("TableHTML")) TextAll=Ctrl("TableHTML").Config.ToString();
		if (Ctrl("TableSCHEDULER")) TextAll=dataRows.ToString();
		if (Ctrl("TableGADGET")) TextAll=dataRows.ToString();


		while (TextAll.length>0)
		{
			TextS.push(TextAll.substr(0,3500));
			TextAll=TextAll.substr(3500);
		}
		TextS[0]=TextS[0]?TextS[0]:"";
		TextS[1]=TextS[1]?TextS[1]:"";
		TextS[2]=TextS[2]?TextS[2]:"";
		TextS[3]=TextS[3]?TextS[3]:"";

		Ctrl("o_text1").SetXValue(TextS[0]);
		Ctrl("o_text2").SetXValue(TextS[1]);
		Ctrl("o_text3").SetXValue(TextS[2]);
		Ctrl("o_text4").SetXValue(TextS[3]);
	}
}



///////////////////////////////////////////////////////////////////////////////          
//IMAGENES
var xmlRESULT;
var txtDATA;

function OpenImage(URLImage, event, obj)
{ 
	if (Ctrl("main").GetMode()=="EDIT_WIKI")
	{                                 

		xmlRESULT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_ADJUNTOS"),"<PARAMS ID=\""+Ctrl("ID").GetXValue()+"\"/>");
		Ctrl("AUX").ClearContextMenu();

		//Recorre el xml y crea los items del menu
		var xmlItem, item=0;
		for (xmlItem = xmlRESULT.FirstChild(); xmlItem != null; xmlItem = xmlItem.Next()) {

			if (xmlItem.Name == "ITEM") 
			{
				xmlItem.SetAttr("name","I"+item.toString());
				Ctrl("AUX").AddContextMenu(xmlItem.GetAttr("name"), xmlItem.GetAttr("label"), xmlItem.GetAttr("img"));
				Ctrl("AUX").SetClientEvent("CONTEX_MENU_I"+item.toString(), "Image"+xmlItem.GetAttr("event"));
			} else
				Ctrl("AUX").AddContextMenu("S" + item.toString(), "-", "");
			item++;
		}

		DataTXT=Ctrl("WikiText").DataTXT;        
		Line =parseInt(obj.getAttribute("wiki-line"  ),10);
		Start=parseInt(obj.getAttribute("wiki-column"),10);
		Length=parseInt(obj.getAttribute("wiki-length"),10);

		Ctrl("AUX").OnContextMenu(event);
	} 
} 

function ImageDEL()
{         
	//Actualizo el TEXTO
	var Lineas=DataTXT.split('\n');
	var txtLine=Lineas[Line];
	txtLine=(Start>0?txtLine.substr(0,Start-1):"") + txtLine.substr(Start+Length+1);
	Lineas[Line]=txtLine;
	DataTXT=Lineas.join("\n");

	//Actualizo
	SetWikiData(DataTXT);
}


//Objeto utilizado para levantar los helpers
function objForHelp(pFileType) 
{
	this.HelpType;
	this.m_Parent = Ctrl("main");
	this.m_Value;
	this.m_FileType = pFileType;

	this.processResult = function(pstrResult) 
	{                                       
		var MyXML=new NomadXML(pstrResult);
		var Lineas=DataTXT.split('\n');
		var txtLine=Lineas[Line];      

		var BeforeText=(Start>0?txtLine.substr(0,Start):"");
		var AfterText =txtLine.substr(Start+Length);
		var MiddleText=txtLine.substr(Start+2,Length-4);

		switch(this.m_FileType)
		{
			case "IMAGE":
				var SpaceBefore="";
				while (MiddleText.length>0 && MiddleText.substr(0,1)==" ")	{ SpaceBefore+=" "; MiddleText=MiddleText.substr(1); }

				var SpaceAfter="";
				while (MiddleText.length>0 && MiddleText.substr(MiddleText.length-1,1)==" ")	{ SpaceAfter+=" "; MiddleText=MiddleText.substr(0,MiddleText.length-1); }

				var AditionalData="";
				if (MiddleText.indexOf("?")>=0)
				{
					AditionalData=MiddleText.substr(MiddleText.indexOf("?"));
					MiddleText=MiddleText.substr(0,MiddleText.indexOf("?"));
				}

				//Actualizo el TEXTO
				txtLine=BeforeText+ "{{"+SpaceBefore+"DB:NucleusRH.Base.Configuracion.Archivos.HEAD:"+MyXML.GetAttr("ID")+AditionalData+SpaceAfter+"}}"+ AfterText;
				break;

			case "LINK":             
				file=MyXML.GetAttr("name").split(".");

				var AditionalData="";
				if (MiddleText.indexOf("|")>=0)
				{
					AditionalData=MiddleText.substr(MiddleText.indexOf("|"));
					MiddleText=MiddleText.substr(0,MiddleText.indexOf("|"));
				} else
				if (MiddleText.indexOf("!")>=0)
				{
					AditionalData=MiddleText.substr(MiddleText.indexOf("!"));
					MiddleText=MiddleText.substr(0,MiddleText.indexOf("!"));
				}

				//Actualizo el TEXTO
				txtLine=BeforeText+"[[DB:NucleusRH.Base.Configuracion.Archivos.HEAD:"+MyXML.GetAttr("ID")+(AditionalData!=""?AditionalData:"!"+MyXML.GetAttr("name"))+"]]"+ AfterText;
				break;
		}
		Lineas[Line]=txtLine;
		DataTXT=Lineas.join("\n");


		//Actualizo
		SetWikiData(DataTXT);
	}

	this.SetFocus = function () 
	{    
	}

}

function ImageCHG(pObj)
{ 
	var it=xmlRESULT.FindElement2("ITEM","name",pObj.ClickContextMenuId);

	//Actualizo el TEXTO
	var Lineas=DataTXT.split('\n');
	var txtLine=Lineas[Line];

	var BeforeText=(Start>0?txtLine.substr(0,Start):"");
	var AfterText =txtLine.substr(Start+Length);
	var MiddleText=txtLine.substr(Start+2,Length-4);

	var SpaceBefore="";
	while (MiddleText.length>0 && MiddleText.substr(0,1)==" ")	{ SpaceBefore+=" "; MiddleText=MiddleText.substr(1); }

	var SpaceAfter="";
	while (MiddleText.length>0 && MiddleText.substr(MiddleText.length-1,1)==" ")	{ SpaceAfter+=" "; MiddleText=MiddleText.substr(0,MiddleText.length-1); }

	var AditionalData="";
	if (MiddleText.indexOf("?")>=0)
	{
		AditionalData=MiddleText.substr(MiddleText.indexOf("?"));
		MiddleText=MiddleText.substr(0,MiddleText.indexOf("?"));
	}

	txtLine=BeforeText+"{{"+SpaceBefore+"DB:NucleusRH.Base.Configuracion.Archivos.HEAD:"+it.GetAttr("text")+AditionalData+SpaceAfter+"}}"+AfterText;
	Lineas[Line]=txtLine;                                                                                                      
	DataTXT=Lineas.join("\n");

	//Actualizo
	SetWikiData(DataTXT);
}

function ImageADD()
{
	var arrParams = new Array();
	var objHelper = new objForHelp("IMAGE");

	arrParams[0] = "DB";
	arrParams[1] = "NucleusRH.Base.Configuracion.Archivos.HEAD"; //FileClass
	arrParams[2] = "nuevo.jpg"; //FileName

	showBrowse(objHelper, arrParams);
}

function SetWikiData(txtDATA)
{
	//Actualizo el ARCHIVO en el SERVIDOR	
	Ctrl("WikiText").SetXValue(txtDATA);
}

///////////////////////////////////////////////////////////////////////////////          
//LINKS
function OpenLink(URLImage, event, obj)
{                
	if (Ctrl("main").GetMode()=="EDIT_WIKI")
	{                                               
		DataTXT=Ctrl("WikiText").DataTXT;        
		Line =parseInt(obj.getAttribute("wiki-line"  ),10);
		Start=parseInt(obj.getAttribute("wiki-column"),10);
		Length=parseInt(obj.getAttribute("wiki-length"),10);

		var Lineas=DataTXT.split('\n');
		var txtLine=Lineas[Line];
		var MiddleText=txtLine.substr(Start+2,Length-4);

		var MODE="ALL";
		if (MiddleText.substr(0,3).toUpperCase()=="DB:") 
			MODE="DB";
		if (MiddleText.substr(0,5).toUpperCase()=="HTML:") 
			MODE="HTML";

		xmlRESULT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_LINKS"),"<PARAMS ID=\""+Ctrl("ID").GetXValue()+"\" MODE=\""+MODE+"\"/>");
		Ctrl("AUX").ClearContextMenu();

		//Recorre el xml y crea los items del menu
		var xmlItem, item=0;
		for (xmlItem = xmlRESULT.FirstChild(); xmlItem != null; xmlItem = xmlItem.Next()) {

			if (xmlItem.Name == "ITEM") 
			{
				xmlItem.SetAttr("name","I"+item.toString());
				Ctrl("AUX").AddContextMenu(xmlItem.GetAttr("name"), xmlItem.GetAttr("label"), xmlItem.GetAttr("img"));
				Ctrl("AUX").SetClientEvent("CONTEX_MENU_I"+item.toString(), "Link"+xmlItem.GetAttr("event"));
			} else
				Ctrl("AUX").AddContextMenu("S" + item.toString(), "-", "");
			item++;
		}

		Ctrl("AUX").OnContextMenu(event);
	} 
} 

