function LinkPAGE(pObj)
{
	var it=xmlRESULT.FindElement2("ITEM","name",pObj.ClickContextMenuId);

	//Actualizo el TEXTO
	var Lineas=DataTXT.split('\n');
	var txtLine=Lineas[Line];
	txtLine=(Start>0?txtLine.substr(0,Start):"") +"[[html:PAGE."+it.GetAttr("text")+".LANG.html!"+it.GetAttr("label")+"]]"+ txtLine.substr(Start+Length);
	Lineas[Line]=txtLine;
	DataTXT=Lineas.join("\n");

	//Actualizo
