//CODIGO
function OpenCode(event, obj)
{ 
	if (Ctrl("main").GetMode()=="EDIT" || Ctrl("main").GetMode()=="NEW")
	{                                 

		xmlRESULT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_MENU"),"<PARAMS ID=\""+Ctrl("PARENT").GetXValue()+"\"/>");
		Ctrl("AUX2").ClearContextMenu();

		//Recorre el xml y crea los items del menu
		var xmlItem, item=0;
		for (xmlItem = xmlRESULT.FirstChild(); xmlItem != null; xmlItem = xmlItem.Next()) {

			if (xmlItem.Name == "ITEM") 
			{

				xmlItem.SetAttr("name","I"+item.toString());
				Ctrl("AUX2").AddContextMenu(xmlItem.GetAttr("name"), xmlItem.GetAttr("label"), xmlItem.GetAttr("img"));
				Ctrl("AUX2").SetClientEvent("CONTEX_MENU_I"+item.toString(), xmlItem.GetAttr("event"));

			} else
				Ctrl("AUX2").AddContextMenu("S" + item.toString(), "-", "");
			item++;
		}

		DataTXT=Ctrl("WikiText").DataTXT;        
		Line =parseInt(obj.getAttribute("wiki-line"  ),10);
		Start=parseInt(obj.getAttribute("wiki-column"),10);
		Length=parseInt(obj.getAttribute("wiki-length"),10);

		Ctrl("AUX2").OnContextMenu(event);
	} 
} 

