///////////////////////////////////////////////////////////////////////////////          
//SCHEDULER
function SCHEDULER_ObjectResult()
{
	this.processResult = function(xmlresult)
	{                                      
		var row;
		var arrrow=new Array();
		var pos,fnd;
		var result=new NomadXML(xmlresult);

		if (result.GetAttr("BUT")=="ACCEPT")
		{          
			//Actualizo el Documento
			fnd=-1;           
			for (pos=0, row=dataRows.FirstChild(); row; row=row.Next(), pos++)
			{               
				arrrow[pos]=row;
				if (row.GetAttr("id")==result.GetAttr("id")) 
				{
					arrrow[pos]=result;
					fnd=pos;
				}
			} 
			if (fnd==-1) arrrow[pos]=result;   

			//Armo el XML	
			while(dataRows.FirstChild()) dataRows.DeleteChild(dataRows.FirstChild());
			for (pos=0; pos<arrrow.length; pos++)
				dataRows.AddText(arrrow[pos].ToString());

			//Actualizo la Tabla	
			TableSCHEDULER_Refresh();
		}
	}
}

function SCHEDULER_ADD()
{
	var row;
	var newID=0;

	//Cargo el Array
	for (row=dataRows.FirstChild(); row; row=row.Next())
		if (row.GetAttrInt("id")>newID)
			newID=row.GetAttrInt("id")
	newID++;

	openNewFlowWait("NucleusRH.Base.Configuracion.Paginas.PAGINA.MAIN.STD.flow", "GUIA_SCHEDULER", '<row id="'+newID+'" txt_ini="*" txt_fin="*" txt_anno="*" txt_page="" />', new SCHEDULER_ObjectResult(), "L");
}

function SCHEDULER_EDT()
{
	var row=dataRows.FindElement2("row","id",Ctrl("TableSCHEDULER").GetXValue());
	if (!row) return;

	openNewFlowWait("NucleusRH.Base.Configuracion.Paginas.PAGINA.MAIN.STD.flow", "GUIA_SCHEDULER", row.ToString(), new SCHEDULER_ObjectResult(), "L");
}

function SCHEDULER_DEL()
{
	var row=dataRows.FindElement2("row","id",Ctrl("TableSCHEDULER").GetXValue());
	if (!row) return;

	dataRows.DeleteChild(row);
	TableSCHEDULER_Refresh();
	return;
}

function SCHEDULER_UP()
{
	var row;
	var arrrow=new Array();
	var pos, fnd;

	//Cargo el Array
	fnd=-1;
	for (pos=0, row=dataRows.FirstChild(); row; row=row.Next(), pos++)
	{               
		arrrow[pos]=row;
		if (row.GetAttr("id")==Ctrl("TableSCHEDULER").GetXValue()) 
			fnd=pos;
	}    

	if (fnd<=0) return;

	//Subo
	row=arrrow[fnd-1];
	arrrow[fnd-1]=arrrow[fnd];
	arrrow[fnd]=row;

	//Armo el XML	
	while(dataRows.FirstChild()) dataRows.DeleteChild(dataRows.FirstChild());
	for (pos=0; pos<arrrow.length; pos++)
		dataRows.AddText(arrrow[pos].ToString());

	//Actualizo la Tabla	
	TableSCHEDULER_Refresh();
}

function SCHEDULER_DW()
{
	var row;
	var arrrow=new Array();
	var pos, fnd;

	//Cargo el Array
	fnd=-1;
	for (pos=0, row=dataRows.FirstChild(); row; row=row.Next(), pos++)
	{               
		arrrow[pos]=row;
		if (row.GetAttr("id")==Ctrl("TableSCHEDULER").GetXValue()) 
			fnd=pos;
	}    

	if (fnd<0 || fnd>=arrrow.length-1) return;

	//Subo
	row=arrrow[fnd+1];
	arrrow[fnd+1]=arrrow[fnd];
	arrrow[fnd]=row;

	//Armo el XML	
	while(dataRows.FirstChild()) dataRows.DeleteChild(dataRows.FirstChild());
	for (pos=0; pos<arrrow.length; pos++)
		dataRows.AddText(arrrow[pos].ToString());

	//Actualizo la Tabla	
	TableSCHEDULER_Refresh();
}


function GADGET_ObjectResult(selID)
{                                 
	this.RowID=selID;

	this.processResult = function(xmlresult)
	{        
		var result=new NomadXML(xmlresult);

		if (result.GetAttr("BUT")=="ACCEPT")
		{          
			var row=dataRows.FindElement2("row","id",this.RowID);
			if (!row) return;

		  	var data=GetGadgetStyle(false).FindElement2("param","name",this.RowID);
		  	if (!data) return; 

		  	if (result.GetAttr("type")!="ENUM")
            {
			row.SetAttr("txt_value",result.GetAttr("selectID"));
			row.SetAttr("value"    ,result.GetAttr("selectID")); 
			}
			else
			{
			var dataval=data.FirstChild().FindElement2("ROW","id",result.GetAttr("selectID"));   
			row.SetAttr("txt_value",dataval.GetAttr("text"));
			row.SetAttr("value"    ,dataval.GetAttr("id"));
			}

			//Actualizo la Tabla	
			TableGADGET_Refresh();
		}
	}
}

function GADGET_EDT()
{   
	var value="";

	var row=dataRows.FindElement2("row","id",Ctrl("TableGADGET").GetXValue());
	if (!row) return;

  	var data=GetGadgetStyle(false).FindElement2("param","name",row.GetAttr("id"));
    if(!data) return;

    if(row.GetAttr("value"))    
    	value=row.GetAttr("value");

    if(!data.FirstChild())
    	openNewFlowWait("NucleusRH.Base.Configuracion.Paginas.PAGINA.MAIN.STD.flow", "GUIA_GADGET_"+row.GetAttr("txt_type").toUpperCase(),"<SOURCE selectID=\""+value+"\" />", new GADGET_ObjectResult(row.GetAttr("id")), "S");
    else
		openNewFlowWait("NucleusRH.Base.Configuracion.Paginas.PAGINA.MAIN.STD.flow", "GUIA_GADGET_"+row.GetAttr("txt_type").toUpperCase(), data.FirstChild().ToString(), new GADGET_ObjectResult(row.GetAttr("id")), "S");
}

function GetGadgetStyle(force)
{ 
	if (valuesRows==null || force)
	{      
		valuesRows=null;
		var MyREPORT=GetProxy().FileService().LoadFileXML("HTML",Ctrl("d_estilo_2").GetXValue()+".xml");

		MyREPORT=MyREPORT.FindElement("html:xslt");
		MyREPORT=MyREPORT.FindElement2("xsl:template","name","GADGET_PARAM");

		valuesRows=MyREPORT;		
	}                 

	return valuesRows;
}


function GadgetStyleChange(obj)
{      
	if (obj.GetXValue()=="")
	{     
		dataRows=new NomadXML("<ROWS></ROWS>");
		TableGADGET_Refresh();
	} else
	{                     
		var MyREPORT=GetGadgetStyle(true);

		if (MyREPORT!=null)
		{
			var row, cur, pos;
			for (pos=1,cur=MyREPORT.FirstChild(); cur; cur=cur.Next(), pos++)
			{             
				row=dataRows.AddTailElement("ROW");
				row.SetAttr("id",cur.GetAttr("name"));
				row.SetAttr("txt_param",cur.GetAttr("name"));
				row.SetAttr("txt_descr",cur.GetAttr("label"));
				row.SetAttr("txt_type" ,cur.GetAttr("type"));
				row.SetAttr("txt_value","");
				row.SetAttr("value","");
			}
		}

		TableGADGET_Refresh();
	}
}

